@Composable
fun Counter() {
  // remember — survives recomposition, lost on rotation if Activity recreates
  var count by remember { mutableStateOf(0) }

  // rememberSaveable — survives rotation + process death (for Parcelable / primitives)
  var draft by rememberSaveable { mutableStateOf("") }

  Column {
    Text("Count: \$count")
    Button(onClick = { count++ }) { Text("+") }
    TextField(value = draft, onValueChange = { draft = it })
  }
}

// Key-based invalidation — recompute when key changes
@Composable
fun ExpensiveCalc(input: String) {
  val result = remember(input) { input.reversed().chunked(3) }
  Text(result.joinToString())
}

// Custom Saver for non-Parcelable types
data class Filters(val query: String, val tags: List<String>)

val FiltersSaver = listSaver<Filters, Any>(
  save = { listOf(it.query, it.tags) },
  restore = { Filters(it[0] as String, @Suppress("UNCHECKED_CAST") (it[1] as List<String>)) }
)

@Composable
fun SearchBar() {
  var filters by rememberSaveable(stateSaver = FiltersSaver) {
    mutableStateOf(Filters("", emptyList()))
  }
  // ...
}

@Composable
fun TodoList() {
  val items = remember { mutableStateListOf("buy milk", "write tests") }
  var draft by remember { mutableStateOf("") }

  Column {
    items.forEach { Text("- \$it") }
    Row {
      TextField(value = draft, onValueChange = { draft = it })
      Button(onClick = { items += draft; draft = "" }) { Text("Add") }
    }
  }
}

// derivedStateOf — recompose only when derived value changes
@Composable
fun MessagesPane(messages: List<Message>, scrollState: LazyListState) {
  // "isAtBottom" only flips occasionally, even though scroll updates constantly
  val isAtBottom by remember(scrollState) {
    derivedStateOf {
      val last = scrollState.layoutInfo.visibleItemsInfo.lastOrNull()?.index ?: -1
      last == messages.lastIndex
    }
  }

  if (!isAtBottom) {
    Button(onClick = { /* scroll down */ }) { Text("Jump to latest") }
  }
}

