// Before — stateful, hard to reuse
@Composable
fun StatefulSearchBar() {
  var query by remember { mutableStateOf("") }
  TextField(value = query, onValueChange = { query = it })
}

// After — stateless, hoisted
@Composable
fun SearchBar(
  query: String,
  onQueryChange: (String) -> Unit,
  modifier: Modifier = Modifier
) {
  TextField(value = query, onValueChange = onQueryChange, modifier = modifier)
}

// Stateful wrapper — keeps backward compat & convenience
@Composable
fun SearchBar(modifier: Modifier = Modifier) {
  var query by rememberSaveable { mutableStateOf("") }
  SearchBar(query, { query = it }, modifier)
}

// Real flow — ViewModel owns state, screen hoists
@Composable
fun SearchScreen(vm: SearchViewModel = hiltViewModel()) {
  val state by vm.state.collectAsStateWithLifecycle()
  SearchScreenContent(
    query = state.query,
    results = state.results,
    onQueryChange = vm::setQuery,
    onSelect = vm::open
  )
}

@Composable
fun SearchScreenContent(
  query: String,
  results: List<Item>,
  onQueryChange: (String) -> Unit,
  onSelect: (Item) -> Unit
) {
  Column {
    SearchBar(query, onQueryChange)
    LazyColumn { items(results) { Row(modifier = Modifier.clickable { onSelect(it) }) { Text(it.name) } } }
  }
}

