// State + ViewModel
data class HomeUiState(val isLoading: Boolean = false, val items: List<Post> = emptyList(), val error: String? = null)

class HomeViewModel(private val repo: PostsRepo) : ViewModel() {
  private val _state = MutableStateFlow(HomeUiState(isLoading = true))
  val state: StateFlow<HomeUiState> = _state.asStateFlow()

  init { reload() }

  fun reload() = viewModelScope.launch {
    _state.update { it.copy(isLoading = true, error = null) }
    val result = runCatching { repo.fetch() }
    _state.update {
      result.fold(
        onSuccess = { items -> it.copy(isLoading = false, items = items) },
        onFailure = { e -> it.copy(isLoading = false, error = e.message) }
      )
    }
  }
}

// Screen
import androidx.lifecycle.compose.collectAsStateWithLifecycle

@Composable
fun HomeScreen(vm: HomeViewModel = hiltViewModel()) {
  val state by vm.state.collectAsStateWithLifecycle()
  HomeContent(
    state = state,
    onRefresh = vm::reload
  )
}

@Composable
fun HomeContent(state: HomeUiState, onRefresh: () -> Unit) {
  Column {
    Button(onClick = onRefresh) { Text("Refresh") }
    when {
      state.isLoading -> CircularProgressIndicator()
      state.error != null -> Text("Error: \${state.error}")
      else -> LazyColumn { items(state.items) { Text(it.title) } }
    }
  }
}

