// Network call when key changes
@Composable
fun User(id: String) {
  var user by remember { mutableStateOf<User?>(null) }
  LaunchedEffect(id) {                           // restarts when id changes
    user = api.fetchUser(id)
  }
  Text(user?.name ?: "loading...")
}

// Subscription with cleanup
@Composable
fun BatteryWatcher(onBatteryLow: () -> Unit) {
  val context = LocalContext.current
  DisposableEffect(Unit) {
    val receiver = object : BroadcastReceiver() { /* ... */ }
    context.registerReceiver(receiver, IntentFilter(Intent.ACTION_BATTERY_LOW))
    onDispose { context.unregisterReceiver(receiver) }
  }
}

// SideEffect — push state to non-Compose listener after recomposition
@Composable
fun TrackPage(title: String) {
  SideEffect { Analytics.track("page", title) }
  // body...
}

// produceState — encapsulate value + producer
@Composable
fun userState(id: String): State<User?> = produceState<User?>(initialValue = null, key1 = id) {
  value = api.fetchUser(id)
}

// rememberCoroutineScope — launch from a click
@Composable
fun SaveButton(onSave: suspend () -> Unit) {
  val scope = rememberCoroutineScope()
  Button(onClick = { scope.launch { onSave() } }) { Text("Save") }
}

// ❌ Lambda allocated every recomposition — defeats skipping
@Composable
fun Bad(items: List<Int>) {
  Row {
    items.forEach { i ->
      Button(onClick = { println(i) }) { Text("\$i") } // new lambda each time
    }
  }
}

// ✅ Stable lambdas
@Composable
fun Good(items: List<Int>, onClick: (Int) -> Unit) {
  Row {
    items.forEach { i -> Button(onClick = { onClick(i) }) { Text("\$i") } }
  }
}

// ❌ Unstable parameter — Compose can't skip
class Holder(val items: MutableList<String>)
@Composable
fun BadCard(holder: Holder) { Text(holder.items.first()) }

// ✅ Stable — Immutable wrapper or value type
@Immutable data class TitleCard(val title: String, val subtitle: String)

// ❌ Read state high in the tree
@Composable
fun ParentRead(text: String) { Header(); Body(); Text(text) }
// Re-runs Header + Body every text change

// ✅ Push read down
@Composable
fun Parent() { Header(); Body(); BodyText() }
@Composable
fun BodyText() {
  val text by viewModel.text.collectAsStateWithLifecycle()
  Text(text)              // only this recomposes
}

